mapper.select:
SELECT 
FROM hub_order_status_sync_schedule s
JOIN users u ON u.id = s.user_id
WHERE s.user_id = #{userId}
  AND s.id = #{id}

mapper.delete:
DELETE FROM hub_order_status_sync_schedule
WHERE user_id = #{userId}
  AND id = #{id}

mapper.update:
UPDATE hub_order_status_sync_schedule_run_log
SET status = 'FAILED',
    finished_at = NOW(),
    error_message = #{errorMessage}
WHERE id = #{id}
